  // Without this, every effect/callback depending on `debouncedSave` would re-run
  // on every render, cascading re-renders through the entire settings tree.
  return useMemo(() => ({
    scheduleSave,
    cancelPendingSave,
    clearPending,
    trackPendingUpdate,
    hasPendingFor,
    pendingSettingsRef,
    pendingEntityIdRef,
    saveTimeoutRef,
  }), [scheduleSave, cancelPendingSave, clearPending, trackPendingUpdate, hasPendingFor]);
}

