    expect(mockUpdateToolSettingsSupabase).not.toHaveBeenCalled();

    await waitFor(() => {
      expect(mockUpdateToolSettingsSupabase).toHaveBeenCalledTimes(1);
    }, { timeout: 1000 });
    expect(mockUpdateToolSettingsSupabase).toHaveBeenCalledWith(
      {
        scope: 'project',
